custom_css:
/*
 * ══════════════════════════════════════════════════════════════
 *  DKU ♛ OLD MONEY — afterdark glass (dark)
 *  DK UNIVERSITY — "Where privilege meets potential" (and profanity)
 *  ultra-modern · glass · phone-like · student RPG certified
 *  Донорские куски: Midnight Ocean (аватар), Bayou (инпут),
 *  Heartbeat (иконки), Wine & Cherry Pie (инфо-чипы)
 * ══════════════════════════════════════════════════════════════
 */
@import url('https://fonts.googleapis.com/css2?family=Unbounded:wght@300;400;600;800&family=Manrope:wght@300;400;500;600;700;800&display=swap');

/* ─────────── PALETTE / TOKENS ─────────── */
:root {
  --dku-accent: #e8c876;
  --dku-accent-2: #9a7bff;
  --dku-accent-rgb: 232, 200, 118;
  --dku-text: #efe9dc;
  --dku-text-dim: #9a917f;
  --dku-glass: rgba(14, 13, 20, 0.72);
  --dku-glass-strong: rgba(18, 16, 26, 0.82);
  --dku-card: rgba(255, 255, 255, 0.05);
  --dku-border: rgba(232, 200, 118, 0.22);
  --dku-border-strong: rgba(232, 200, 118, 0.45);
  --dku-glow: rgba(var(--dku-accent-rgb), 0.35);
  --dku-hover: rgba(var(--dku-accent-rgb), 0.10);
  --dku-on-accent: #17131f;
  --dku-shadow: rgba(0, 0, 0, 0.45);

  --dku-font-display: 'Unbounded', system-ui, sans-serif;
  --dku-font-body: 'Manrope', 'Segoe UI', system-ui, sans-serif;

  --dku-avatar-h: 350px;            /* Midnight Ocean size, do not touch, nerd */
  --dku-radius: 22px;
  --dku-radius-sm: 14px;

  /* words of wisdom (strings) */
  --dku-placeholder: "Say it with your chest, trust-fund bitch… 💸✨";
  --dku-think-label: "GAME PLAN · cooking elite bullshit… (¬‿¬) 🧠🔥";
  --dku-board-label: "📌 CAMPUS BULLETIN · DKU CLASSIFIED";
  --dku-label-id: "PLAY №";
  --dku-label-tokens: "STAT LINE";
  --dku-label-timer: "SHOT CLOCK";
  --dku-swipe-label: "REMATCH ";
  --dku-btn-more: "PLAYBOOK";
  --dku-btn-edit: "REWRITE";
  --dku-badge: " ♛";
  --dku-badge-user: " 💳";
  --dku-deco: "♛";
  --dku-loader: "🎓";

  --dku-icon-filter: brightness(0) saturate(100%) invert(85%) sepia(28%) saturate(640%) hue-rotate(345deg) brightness(98%) contrast(90%);
}

/* ─────────── KEYFRAMES ─────────── */
@keyframes dku-shimmer {
  0% { background-position: 0% 50%; }
  100% { background-position: -300% 50%; }
}
@keyframes dku-breathe {
  0%, 100% { opacity: 0.55; }
  50% { opacity: 1; }
}
@keyframes dku-board-in {
  from { opacity: 0; transform: translateY(14px) scale(0.985); }
  to { opacity: 1; transform: none; }
}
@keyframes dku-toast-in {
  from { opacity: 0; transform: translateY(-16px) scale(0.95); }
  to { opacity: 1; transform: none; }
}
@keyframes dku-loader-spin {
  from { transform: rotate(0deg) scale(2.4); }
  to { transform: rotate(360deg) scale(2.4); }
}
@keyframes dku-pulse-border {
  0%, 100% { box-shadow: 0 0 0 0 rgba(var(--dku-accent-rgb), 0.25); }
  50% { box-shadow: 0 0 18px 2px rgba(var(--dku-accent-rgb), 0.35); }
}

/* ─────────── BASE ─────────── */
body, html {
  color: var(--dku-text) !important;
  font-family: var(--dku-font-body) !important;
  font-weight: 400;
}

/* headings — zero classicism, pure display grotesque */
.standoutHeader strong,
#right-nav-panel h2,
.drawer-content > h3,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter),
.drawer-content .flex-container .flex-container h3:first-of-type,
.popup h3:not(dialog *) {
  font-family: var(--dku-font-display) !important;
  font-size: calc(var(--mainFontSize) * 0.95);
  font-weight: 600;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--dku-text);
  line-height: 2;
  white-space: nowrap;
}
.standoutHeader strong::before,
#right-nav-panel h2::before,
.drawer-content > h3::before,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter)::before,
.drawer-content .flex-container .flex-container h3:first-of-type::before,
.popup h3:not(dialog *)::before {
  content: var(--dku-deco);
  margin-right: 0.45em;
  background: linear-gradient(120deg, var(--dku-accent), var(--dku-accent-2), var(--dku-accent));
  background-size: 300% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  -webkit-text-fill-color: transparent;
  animation: dku-shimmer 7s linear infinite;
  text-shadow: none;
}

/* drawers headers — thin neon spine, no baroque */
.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#top-settings-holder h4:not(#ai-config-button *):not(#rightNavHolder *) {
  border-width: 0 0 0 3px !important;
  border-style: solid;
  border-color: transparent !important;
  border-radius: 0;
  background-image: none !important;
  padding-left: 8px;
  border-image: linear-gradient(to bottom, transparent 20%, var(--dku-accent) 20%, var(--dku-accent-2) 80%, transparent 80%) 1 100%;
}
.inline-drawer-icon { font-size: calc(var(--mainFontSize) * 0.9); }

/* ─────────── SCROLLBAR ─────────── */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar:horizontal { height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb:vertical,
::-webkit-scrollbar-thumb:horizontal {
  background: linear-gradient(to bottom, var(--dku-accent), var(--dku-accent-2));
  border-radius: 6px;
  border: 0;
  box-shadow: none;
}

/* ─────────── INPUTS ─────────── */
input:not(input[type="range"], input[type="checkbox"]),
select, .text_pole, .textarea_compact,
textarea:not(.select2-search__field, #send_textarea) {
  background: var(--dku-card) !important;
  border: 1px solid var(--dku-border) !important;
  border-radius: 10px !important;
  color: var(--dku-text) !important;
}
select:focus-visible, input:focus-visible,
textarea:not(#send_textarea):focus-visible {
  outline: none !important;
  border-color: rgba(var(--dku-accent-rgb), 0.7) !important;
  box-shadow: 0 0 10px var(--dku-glow) !important;
}

/* ─────────── CHECKBOXES (Wine&Cherry vibe, but glassier) ─────────── */
input[type="checkbox"] {
  appearance: none;
  -webkit-appearance: none;
  width: 16px;
  height: 16px;
  border-radius: 6px;
  border: 1.5px solid var(--dku-border-strong);
  background: transparent;
  cursor: pointer;
  outline: none;
  position: relative;
  display: inline-block;
  vertical-align: middle;
  transition: all 0.2s ease;
  margin-right: 6px;
  flex-shrink: 0;
}
input[type="checkbox"]:hover { border-color: var(--dku-accent); }
input[type="checkbox"]:checked {
  background: linear-gradient(135deg, var(--dku-accent), var(--dku-accent-2));
  border-color: transparent;
  box-shadow: 0 0 10px var(--dku-glow);
}
input[type="checkbox"]:checked::after {
  content: "✓";
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -52%);
  font-size: 11px;
  font-weight: 800;
  color: var(--dku-on-accent);
  line-height: 1;
}
input[type="checkbox"]::before { content: none !important; }

/* ─────────── BUTTONS ─────────── */
.menu_button:not(.mes_edit_buttons *) {
  background: var(--dku-card);
  border: 1px solid var(--dku-border);
  border-radius: 10px;
  color: var(--dku-text);
  transition: all 0.2s ease;
}
.menu_button:not(.mes_edit_buttons *):hover {
  background: var(--dku-hover);
  border-color: rgba(var(--dku-accent-rgb), 0.6);
  box-shadow: 0 0 12px var(--dku-glow);
}
#delete_button, #dialogue_del_mes_ok, #dialogue_popup_ok,
#bulk_tag_popup_reset, #bulk_tag_popup_remove_mutual,
.mes_edit_cancel.menu_button, .menu_button.popup-button-ok, .redWarningBG {
  background-color: var(--crimson70a) !important;
  color: var(--white100) !important;
}

/* ─────────── TOP BAR — floating glass, phone status-bar energy ─────────── */
#top-bar, body.no-blur #top-bar {
  background: var(--dku-glass) !important;
  backdrop-filter: blur(28px) saturate(160%) !important;
  -webkit-backdrop-filter: blur(28px) saturate(160%) !important;
  border: 1px solid var(--dku-border) !important;
  border-top: none !important;
  border-radius: 0 0 20px 20px !important;
  box-shadow: 0 14px 40px var(--dku-shadow) !important;
}

/* Heartbeat-style icon swap: humans can actually read these */
#top-settings-holder .drawer-icon.fa-fw {
  display: flex;
  overflow: visible;
  justify-content: center;
  align-items: center;
  font-size: 0 !important;
  width: 26px !important;
  height: 26px !important;
  min-width: 26px;
  transition: filter 0.2s ease, transform 0.2s ease;
}
#top-settings-holder .drawer-icon.fa-fw::before {
  font-size: 0 !important;
  content: "" !important;
  display: inline-block !important;
  width: 22px !important;
  height: 22px !important;
  background-size: contain !important;
  background-repeat: no-repeat !important;
  background-position: center !important;
  filter: var(--dku-icon-filter) !important;
}
#top-settings-holder .drawer-icon.fa-fw:hover,
#top-settings-holder .drawer-icon.fa-fw.openIcon {
  transform: translateY(-1px) !important;
}
#top-settings-holder .drawer-icon.fa-fw:hover::before,
#top-settings-holder .drawer-icon.fa-fw.openIcon::before {
  filter: var(--dku-icon-filter) drop-shadow(0 0 6px rgba(var(--dku-accent-rgb), 0.8)) !important;
}
/* left = tuning sliders → menu; right = character roster → list */
#leftNavDrawerIcon::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/menu_outline_24.svg") !important; }
#rightNavDrawerIcon::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/list_24.svg") !important; }
#advanced-formatting-button .drawer-icon::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/text_outline_24.svg") !important; }
#WI-SP-button .drawer-icon::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/globe_outline_24.svg") !important; }
#user-settings-button .drawer-icon::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/gear_outline_24.svg") !important; }
#backgrounds-drawer-toggle .drawer-icon::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/picture_outline_24.svg") !important; }
#extensions-settings-button .drawer-icon::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/cube_box_outline_24.svg") !important; }
#persona-management-button .drawer-icon::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/user_circle_outline_24.svg") !important; }

/* API status: link when alive, cancel when dead */
#API-status-top { font-size: 0 !important; width: 26px !important; height: 26px !important; display: flex; align-items: center; justify-content: center; }
#API-status-top::before {
  font-size: 0 !important;
  content: "" !important;
  display: inline-block !important;
  width: 22px !important;
  height: 22px !important;
  background-size: contain !important;
  background-repeat: no-repeat !important;
  background-position: center !important;
  filter: var(--dku-icon-filter) !important;
}
#API-status-top:not(.redOverlayGlow)::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/link_24.svg") !important; }
#API-status-top.redOverlayGlow::before {
  background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/cancel_outline_24.svg") !important;
  filter: brightness(0) saturate(100%) invert(30%) sepia(90%) saturate(3000%) hue-rotate(345deg) brightness(95%) contrast(95%) !important;
}

/* ─────────── CHAT / MESSAGES ───────────
   Layout: Midnight Ocean (fullwidth 350px avatar on top, smooth fade)
   Info design: Wine & Cherry Pie (labeled stat chips, big name, pills) */
.mes::before { display: none !important; }

#chat .mes, body.bubblechat .mes {
  display: flex !important;
  flex-direction: column !important;
  position: relative;
  margin-bottom: 46px !important;
  border: 1px solid var(--dku-border) !important;
  border-radius: var(--dku-radius) !important;
  padding: 0 !important;
  box-shadow: 0 10px 30px var(--dku-shadow);
  overflow: visible !important;
  height: auto !important;
  max-height: none !important;
  z-index: 0;
}
#chat .mes:last-of-type { margin-bottom: 20px !important; }

/* avatar strip — exact Midnight Ocean sizing, both user & char */
.mes .mesAvatarWrapper,
#chat .mes .mesAvatarWrapper {
  height: var(--dku-avatar-h) !important;
  width: 100% !important;
  min-width: 100% !important;
  position: relative !important;
  overflow: hidden !important;
  order: -1 !important;
  display: flex;
  align-items: flex-start;
  margin: 0 !important;
  padding: 0 !important;
  background: transparent !important;
  box-shadow: none !important;
  flex: 0 0 var(--dku-avatar-h) !important;
  float: none !important;
  border-radius: var(--dku-radius) var(--dku-radius) 0 0 !important;
}
.mes .mesAvatarWrapper .avatar {
  position: absolute;
  top: 0; left: 0;
  width: 100% !important;
  height: 100% !important;
  margin: 0 !important;
  z-index: 0;
  -webkit-mask-image: linear-gradient(to bottom, black 60%, transparent 100%) !important;
  mask-image: linear-gradient(to bottom, black 60%, transparent 100%) !important;
  pointer-events: none !important;
}
.mes .avatar img,
.mes[is_user="true"] .avatar img,
.mes[is_user="false"] .avatar img {
  --img-scale: 1;
  --img-x: 50%;
  --img-y: 0%;
  width: 100% !important;
  height: 100% !important;
  object-fit: cover !important;
  object-position: var(--img-x) var(--img-y) !important;
  transform: scale(var(--img-scale));
  transform-origin: var(--img-x) var(--img-y);
  transition: transform 0.3s ease;
  border: none !important;
  border-radius: 0 !important;
  outline: none !important;
  box-shadow: none !important;
  padding: 0 !important;
  background-color: transparent !important;
}

/* message body */
#chat .mes .mes_block {
  padding: 14px 16px 14px !important;
  position: relative;
  overflow: visible !important;
  height: auto !important;
  max-height: none !important;
  min-height: 0 !important;
  flex: 1 1 auto !important;
  width: 100% !important;
  min-width: 0 !important;
  clear: both !important;
}
.mes_text {
  overflow: visible !important;
  height: auto !important;
  max-height: none !important;
  padding: 6px 4px 8px !important;
  line-height: 1.75 !important;
}

/* ── stat chips over avatar (Wine&Cherry labels, sports renamed) ── */
.mes .mesIDDisplay,
.mes .tokenCounterDisplay,
.mes .mes_timer {
  position: absolute !important;
  z-index: 25 !important;
  left: auto !important;
  background: var(--dku-glass-strong) !important;
  backdrop-filter: blur(14px) saturate(150%) !important;
  -webkit-backdrop-filter: blur(14px) saturate(150%) !important;
  border: 1px solid var(--dku-border) !important;
  padding: 4px 10px !important;
  border-radius: 12px !important;
  font-family: var(--dku-font-body) !important;
  font-size: 11px !important;
  font-weight: 600 !important;
  letter-spacing: 0.04em;
  white-space: nowrap !important;
  color: var(--dku-text) !important;
  display: block !important;
  opacity: 1 !important;
  visibility: visible !important;
  text-shadow: none !important;
}
.mes .mesIDDisplay { top: 10px !important; right: 10px !important; text-align: right !important; }
.mes .tokenCounterDisplay { top: 10px !important; left: 10px !important; right: auto !important; text-align: left !important; }
.mes .mes_timer { top: 58px !important; left: 10px !important; right: auto !important; text-align: left !important; }

.mes .mesIDDisplay::before,
.mes .tokenCounterDisplay::before,
.mes .mes_timer::before {
  display: block;
  font-family: var(--dku-font-display);
  font-weight: 600;
  font-size: 7px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  margin-bottom: 2px;
  background: linear-gradient(120deg, var(--dku-accent), var(--dku-accent-2), var(--dku-accent));
  background-size: 300% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  -webkit-text-fill-color: transparent;
  animation: dku-shimmer 7s linear infinite;
}
.mes .mesIDDisplay::before { content: var(--dku-label-id); }
.mes .tokenCounterDisplay::before { content: var(--dku-label-tokens); }
.mes .mes_timer::before { content: var(--dku-label-timer); }
.mes .mesIDDisplay:empty, .mes .tokenCounterDisplay:empty, .mes .mes_timer:empty { display: none !important; }
.tokenCounterDisplay::after { display: none !important; }

/* ── name over the fade (luxury nameplate) ── */
.mes .ch_name { position: static !important; }
.mes .ch_name .name_text {
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  top: -58px; /* floats up into the avatar fade (mes_block anchor) */
  z-index: 12;
  white-space: nowrap;
  max-width: 92%;
  overflow: hidden;
  text-overflow: ellipsis;
  font-family: var(--dku-font-display);
  font-size: 19px;
  font-weight: 600;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--dku-text);
  text-shadow: 0 2px 20px var(--dku-shadow), 0 1px 4px var(--dku-shadow);
}
.mes .ch_name .name_text::after {
  content: var(--dku-badge);
  font-size: 15px;
  background: linear-gradient(120deg, var(--dku-accent), var(--dku-accent-2));
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  -webkit-text-fill-color: transparent;
}
.mes[is_user="true"] .ch_name .name_text::after { content: var(--dku-badge-user); }

.mes[is_system="true"] .ch_name .name_text {
  position: static;
  transform: none;
  font-size: 13px;
}

/* timestamp — tiny receipt line under the name */
.mes .timestamp {
  position: absolute;
  top: -32px;
  left: 0; right: 0;
  margin: 0 auto;
  width: fit-content;
  z-index: 12;
  font-family: var(--dku-font-body);
  font-weight: 500;
  font-size: 10px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  opacity: 0.6;
  color: var(--dku-text-dim);
}
.timestamp-icon { display: none !important; }

/* ── message action pill (Wine&Cherry style, meme labels) ── */
.mes .mes_buttons {
  position: relative !important;
  display: inline-flex !important;
  flex-direction: row !important;
  justify-content: center !important;
  align-items: center !important;
  width: auto !important;
  min-width: 170px !important;
  margin: 10px auto 6px !important;
  gap: 0 !important;
  z-index: 20 !important;
  background: var(--dku-glass-strong) !important;
  backdrop-filter: blur(12px) !important;
  -webkit-backdrop-filter: blur(12px) !important;
  border: 1px solid var(--dku-border) !important;
  border-radius: 20px !important;
  padding: 5px 14px !important;
  transition: all 0.2s ease !important;
  opacity: 1 !important;
  visibility: visible !important;
}
.mes .mes_buttons:hover {
  border-color: rgba(var(--dku-accent-rgb), 0.55) !important;
  box-shadow: 0 0 14px var(--dku-glow) !important;
}
.mes .mes_button {
  background: transparent !important;
  border: none !important;
  box-shadow: none !important;
  text-shadow: none !important;
  color: var(--dku-text-dim) !important;
  font-size: 0 !important;
}
.mes_buttons > .mes_button.fa-ellipsis,
.mes_buttons > .mes_button.fa-pencil {
  width: auto !important;
  height: auto !important;
  padding: 0 6px !important;
  margin: 0 !important;
  border-radius: 0 !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 5px;
  opacity: 1 !important;
  visibility: visible !important;
  position: relative !important;
  z-index: 21 !important;
}
.mes .mes_button:hover, .mes .mes_button:focus, .mes .mes_button:active {
  background: transparent !important;
  border: none !important;
  color: var(--dku-accent) !important;
  filter: none !important;
}
.mes_buttons > .mes_button.fa-ellipsis::before {
  content: "👀" !important;
  font-size: 12px !important;
  line-height: 1 !important;
}
.mes_buttons > .mes_button.fa-ellipsis::after {
  content: var(--dku-btn-more) !important;
  font-family: var(--dku-font-display) !important;
  font-size: 9px !important;
  font-weight: 600 !important;
  letter-spacing: 0.14em !important;
  text-transform: uppercase;
  opacity: 1 !important;
}
.mes_buttons > .mes_button.fa-pencil::before {
  content: "✍️" !important;
  font-size: 12px !important;
  line-height: 1 !important;
}
.mes_buttons > .mes_button.fa-pencil::after {
  content: var(--dku-btn-edit) !important;
  font-family: var(--dku-font-display) !important;
  font-size: 9px !important;
  font-weight: 600 !important;
  letter-spacing: 0.14em !important;
  text-transform: uppercase;
  opacity: 1 !important;
}
.mes_buttons:has(.extraMesButtons.visible) > .mes_button.fa-ellipsis,
.mes_buttons:has(.extraMesButtons.visible) > .mes_button.fa-pencil { display: none !important; }
.extraMesButtons.visible .mes_button {
  font-size: 13px !important;
  justify-content: center !important;
  border-radius: 6px !important;
  padding: 2px 5px !important;
}
#chat .mes_block .mes_edit_buttons {
  position: absolute !important;
  bottom: -40px !important;
  left: 50% !important;
  transform: translateX(-50%) !important;
  right: auto !important;
  z-index: 30 !important;
}

/* ── swipes: absolute bottom, "REMATCH 2/5" counter ── */
#chat .mes .swipeLeftBlock, #chat .mes .swipeRightBlock { position: static !important; transform: none !important; }
.swipe_left, .swipe_right, .swipe_info, .swipes-counter {
  position: absolute !important;
  bottom: 8px !important;
  top: auto !important;
  z-index: 10 !important;
  transform: none !important;
  color: var(--dku-text-dim) !important;
}
.swipe_info, .swipes-counter {
  left: 0 !important; right: 0 !important;
  margin: 0 auto !important;
  width: fit-content !important;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--dku-font-body);
  font-size: 11px !important;
  font-weight: 600;
}
.swipe_info::before, .swipes-counter::before {
  content: var(--dku-swipe-label);
  font-family: var(--dku-font-display);
  font-size: 8px;
  font-weight: 600;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  margin-right: 6px;
  background: linear-gradient(120deg, var(--dku-accent), var(--dku-accent-2));
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  -webkit-text-fill-color: transparent;
}
.swipe_left { left: auto !important; right: 50% !important; margin-right: 80px !important; }
.swipe_right { right: auto !important; left: 50% !important; margin-left: 80px !important; }
.swipe_left, .swipe_right {
  font-size: 13px !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  bottom: 5px !important;
  opacity: 0.7;
}
.swipe_left:hover, .swipe_right:hover { color: var(--dku-accent) !important; opacity: 1; }

/* ── reasoning / thinking (locker-room talk) ── */
.mes_reasoning, .mes_reasoning_details {
  position: relative !important;
  z-index: 150 !important;
  background: var(--dku-glass-strong) !important;
  backdrop-filter: blur(14px) saturate(130%) !important;
  -webkit-backdrop-filter: blur(14px) saturate(130%) !important;
  border: 1px solid var(--dku-border) !important;
  border-radius: var(--dku-radius-sm) !important;
  box-shadow: 0 6px 20px var(--dku-shadow) !important;
  transition: all 0.25s ease !important;
}
.mes_reasoning {
  border-left: 3px solid var(--dku-accent) !important;
  padding: 10px 14px !important;
  margin: 8px auto 14px !important;
  width: 94% !important;
}
div.mes_reasoning:hover { border-color: rgba(var(--dku-accent-rgb), 0.5) !important; }
.mes_reasoning_details { border: none !important; background: transparent !important; box-shadow: none !important; }
.mes_reasoning_header {
  background: transparent !important;
  backdrop-filter: none !important;
  border: none !important;
  box-shadow: none !important;
  padding: 0 !important;
  display: flex !important;
  justify-content: center !important;
  align-items: center !important;
  width: fit-content !important;
  margin: 0 auto !important;
}
div.mes_reasoning_actions { position: absolute !important; width: auto !important; z-index: 10 !important; }
div.mes_reasoning_arrow.fa-solid.fa-chevron-up::before { color: transparent !important; opacity: 0 !important; }
.mes_reasoning_header_title {
  position: relative;
  cursor: pointer;
  font-size: 0 !important;
  line-height: 0 !important;
  padding: 4px 12px 2px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  white-space: nowrap;
  background: none;
  border: none;
}
.mes_reasoning_header_title::after {
  content: var(--dku-think-label) !important;
  font-family: var(--dku-font-display);
  font-size: 9px !important;
  font-weight: 600 !important;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  line-height: normal;
  background: linear-gradient(120deg, var(--dku-text-dim), var(--dku-accent), var(--dku-accent-2), var(--dku-text-dim));
  background-size: 300% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent !important;
  -webkit-text-fill-color: transparent !important;
  text-shadow: none !important;
  animation: dku-shimmer 4s linear infinite !important;
}
.mes:has(.mes_reasoning) .mes_buttons { margin-bottom: 0 !important; }

/* quotes — glass pills */
.mes_text q, .mes q {
  line-height: 1.85 !important;
  display: inline !important;
  -webkit-box-decoration-break: clone !important;
  box-decoration-break: clone !important;
  padding: 1px 7px !important;
  border-radius: 7px;
  background: rgba(var(--dku-accent-rgb), 0.10);
  border: 1px solid rgba(var(--dku-accent-rgb), 0.18);
}
.mes_text code {
  background: var(--dku-card) !important;
  border: 1px dashed var(--dku-border-strong) !important;
  border-radius: 7px !important;
  padding: 2px 6px !important;
  font-size: 0.85em !important;
}
.mes_text pre {
  background: var(--dku-card) !important;
  border: 1px solid var(--dku-border) !important;
  border-radius: var(--dku-radius-sm) !important;
  animation: dku-board-in 0.5s ease both;
}

/* ─────────── INFOBOARDS (tables / blockquotes / details) — animated ─────────── */
.mes_text table {
  width: 100%;
  border-collapse: separate !important;
  border-spacing: 0;
  border: 1px solid var(--dku-border) !important;
  border-radius: var(--dku-radius-sm);
  overflow: hidden;
  background: var(--dku-glass-strong);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  animation: dku-board-in 0.55s ease both;
  margin: 10px 0;
}
.mes_text th {
  font-family: var(--dku-font-display);
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  padding: 9px 12px;
  color: var(--dku-on-accent) !important;
  background: linear-gradient(120deg, var(--dku-accent), var(--dku-accent-2), var(--dku-accent)) !important;
  background-size: 300% 100% !important;
  animation: dku-shimmer 9s linear infinite;
  border: none !important;
  text-align: left;
}
.mes_text td {
  padding: 8px 12px;
  border: none !important;
  border-top: 1px solid var(--dku-border) !important;
  font-size: 0.92em;
  transition: background 0.15s ease;
}
.mes_text tr:hover td { background: var(--dku-hover); }

.mes_text blockquote {
  position: relative;
  background: var(--dku-glass-strong);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid var(--dku-border);
  border-left: 3px solid var(--dku-accent);
  border-radius: var(--dku-radius-sm);
  padding: 10px 14px;
  margin: 10px 0;
  animation: dku-board-in 0.55s ease both, dku-pulse-border 5s ease-in-out infinite;
}
.mes_text blockquote::before {
  content: var(--dku-board-label);
  display: block;
  font-family: var(--dku-font-display);
  font-size: 8px;
  font-weight: 600;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  margin-bottom: 5px;
  background: linear-gradient(120deg, var(--dku-accent), var(--dku-accent-2), var(--dku-accent));
  background-size: 300% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  -webkit-text-fill-color: transparent;
  animation: dku-shimmer 6s linear infinite;
}

.mes_text details {
  background: var(--dku-glass-strong);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid var(--dku-border);
  border-radius: var(--dku-radius-sm);
  padding: 8px 14px;
  margin: 10px 0;
  animation: dku-board-in 0.55s ease both;
}
.mes_text details summary {
  cursor: pointer;
  list-style: none;
  font-family: var(--dku-font-display);
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--dku-accent);
}
.mes_text details summary::-webkit-details-marker { display: none; }
.mes_text details summary::before {
  content: "▸";
  display: inline-block;
  margin-right: 8px;
  transition: transform 0.25s ease;
}
.mes_text details[open] summary::before { transform: rotate(90deg); }
.mes_text details[open] summary { margin-bottom: 6px; }

.info-block {
  background: var(--dku-glass-strong) !important;
  border: 1px solid var(--dku-border) !important;
  border-left: 3px solid var(--dku-accent) !important;
  border-radius: var(--dku-radius-sm) !important;
  animation: dku-board-in 0.45s ease both;
}

/* ─────────── SEND FORM — Bayou-sized pill, animated cheese ─────────── */
#send_form, body.no-blur #send_form {
  outline: none !important;
  border: none !important;
  background: var(--dku-glass) !important;
  backdrop-filter: blur(28px) saturate(160%) !important;
  -webkit-backdrop-filter: blur(28px) saturate(160%) !important;
  box-shadow: 0 -10px 30px var(--dku-shadow);
  border-radius: 20px 20px 0 0;
  border-top: 1px solid var(--dku-border) !important;
}
#send_textarea, #send_textarea:focus {
  clip-path: none !important;
  border: none !important;
  backdrop-filter: none !important;
  background: transparent !important;
  color: var(--dku-text) !important;
  font-family: var(--dku-font-body) !important;
  resize: none !important;
  outline: none !important;
  box-shadow: none !important;
}
#nonQRFormItems {
  position: relative;
  margin: 8px 6px;
  border: 1px solid var(--dku-border);
  border-radius: 14px;
  background: var(--dku-card);
  transition: border-color 0.25s ease, box-shadow 0.25s ease;
  display: flex;
  align-items: center;
}
#nonQRFormItems:focus-within {
  border-color: rgba(var(--dku-accent-rgb), 0.65);
  box-shadow: 0 0 14px var(--dku-glow);
}
#send_textarea::placeholder { color: transparent !important; text-shadow: none !important; opacity: 0; }
#nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
  content: var(--dku-placeholder);
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  font-family: var(--dku-font-display);
  font-size: 11px;
  font-weight: 400;
  letter-spacing: 0.12em;
  pointer-events: none;
  z-index: 10;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: calc(100% - 92px);
  background: linear-gradient(90deg, var(--dku-text-dim), var(--dku-accent), var(--dku-accent-2), var(--dku-text-dim));
  background-size: 300% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  -webkit-text-fill-color: transparent;
  animation: dku-shimmer 5s linear infinite, dku-breathe 3.2s ease-in-out infinite;
}

/* bottom-bar icons — Heartbeat technique, human-readable */
#rightSendForm > div, #leftSendForm > div,
#rightSendForm > div > [class*="fa-"], #rightSendForm > div > i, #quickPersona {
  font-size: 16px !important;
}
#rightSendForm > div:not(.mes_stop), #leftSendForm > div { opacity: 1; margin: 0 2px !important; }
#rightSendForm div:hover, #leftSendForm div:hover {
  color: var(--dku-accent) !important;
  filter: drop-shadow(0 0 6px var(--dku-glow)) !important;
}
#options_button, #extensionsMenuButton, #send_but {
  font-size: 0 !important;
  width: 26px !important;
  height: 26px !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
}
#options_button::before, #extensionsMenuButton::before, #send_but::before {
  font-size: 0 !important;
  content: "" !important;
  display: inline-block !important;
  width: 22px !important;
  height: 22px !important;
  background-size: contain !important;
  background-repeat: no-repeat !important;
  background-position: center !important;
  filter: var(--dku-icon-filter) !important;
  transition: filter 0.2s ease;
}
#options_button::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/more_horizontal_24.svg") !important; }
#extensionsMenuButton::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/services_outline_24.svg") !important; }
#send_but::before { background-image: url("https://unpkg.com/@vkontakte/icons/src/svg/24/send_outline_24.svg") !important; }
#options_button:hover::before, #extensionsMenuButton:hover::before, #send_but:hover::before {
  filter: var(--dku-icon-filter) drop-shadow(0 0 6px rgba(var(--dku-accent-rgb), 0.8)) !important;
}
#send_form .mes_stop { padding: 0 7px; opacity: 1; }
#mes_stop i::before { content: "\f04d"; color: #e0455a; }

/* ─────────── PANELS / POPUPS — full glass ─────────── */
#left-nav-panel, #right-nav-panel,
#completion_prompt_manager_popup, #rm_api_block, #AdvancedFormatting,
#WorldInfo, #user-settings-block, #Backgrounds, #rm_extensions_block,
.drawer-content.openDrawer,
body.no-blur .popup, body.no-blur #bulk_tag_popup, body.no-blur #dialogue_popup,
.popup, #character_popup, #world_popup,
#options, #extensionsMenu, .popup .popper-modal,
body.no-blur * .select2-dropdown, .select2-dropdown {
  background: var(--dku-glass) !important;
  backdrop-filter: blur(30px) saturate(160%) !important;
  -webkit-backdrop-filter: blur(30px) saturate(160%) !important;
  border: 1px solid var(--dku-border) !important;
  border-radius: 18px !important;
  padding: 10px;
  box-shadow: 0 20px 50px var(--dku-shadow) !important;
}
.options-content, .list-group { border: none; background: transparent !important; }
#extensionsMenu > .extension_container > div, #extensionsMenu > div:not(.extension_container),
.options-content a, .list-group-item, #qr--bar { opacity: 1 !important; }
.options-content a:hover, .list-group-item:hover {
  background: var(--dku-hover) !important;
  border-radius: 10px;
}

/* zoomed avatar */
.zoomed_avatar {
  border-radius: var(--dku-radius) !important;
  border: 1px solid var(--dku-border) !important;
  box-shadow: 0 24px 60px var(--dku-shadow) !important;
  overflow: hidden;
}
.zoomed_avatar img { border-radius: var(--dku-radius) !important; }

/* ─────────── TOASTS — themed AND actually visible ─────────── */
#toast-container { z-index: 999999 !important; }
#toast-container > div {
  opacity: 1 !important;
  background-color: var(--dku-toast-bg, var(--dku-glass)) !important;
  background-image: none !important;
  backdrop-filter: blur(26px) saturate(160%) !important;
  -webkit-backdrop-filter: blur(26px) saturate(160%) !important;
  border: 1px solid var(--dku-border) !important;
  border-left: 3px solid var(--dku-accent) !important;
  border-radius: 16px !important;
  box-shadow: 0 14px 40px var(--dku-shadow) !important;
  color: var(--dku-text) !important;
  padding: 12px 16px 12px 42px !important;
  animation: dku-toast-in 0.4s cubic-bezier(0.21, 1.02, 0.73, 1) both;
  position: relative;
}
#toast-container > div::before {
  content: "🎓";
  position: absolute;
  left: 12px;
  top: 50%;
  transform: translateY(-50%);
  font-size: 16px;
}
#toast-container > div.toast-success::before { content: "✅"; }
#toast-container > div.toast-error::before { content: "💀"; }
#toast-container > div.toast-warning::before { content: "⚠️"; }
#toast-container > div.toast-info::before { content: "📣"; }
#toast-container > div.toast-success { border-left-color: #6fcf8b !important; }
#toast-container > div.toast-error { border-left-color: #e0455a !important; }
#toast-container > div.toast-warning { border-left-color: #e8a13c !important; }
#toast-container .toast-title {
  font-family: var(--dku-font-display) !important;
  font-weight: 600 !important;
  font-size: 0.72em !important;
  letter-spacing: 0.16em !important;
  text-transform: uppercase !important;
  color: var(--dku-accent) !important;
}
#toast-container .toast-message { color: var(--dku-text) !important; opacity: 0.9 !important; font-size: 0.88em !important; }
#toast-container .toast-close-button { color: var(--dku-text) !important; opacity: 0.4 !important; text-shadow: none !important; }
#toast-container .toast-progress {
  background: linear-gradient(90deg, var(--dku-accent), var(--dku-accent-2)) !important;
  opacity: 0.5 !important;
  height: 3px !important;
  border-radius: 0 0 0 16px;
}

/* ─────────── extensionTopBar ─────────── */
#extensionTopBar, #extensionConnectionProfiles {
  border: none !important;
  border-bottom: 1px solid var(--dku-border) !important;
  border-radius: 0 0 var(--dku-radius-sm) var(--dku-radius-sm) !important;
  background: var(--dku-glass) !important;
  backdrop-filter: blur(20px) !important;
  -webkit-backdrop-filter: blur(20px) !important;
}
#extensionTopBarChatName, #extensionTopBarSearchInput {
  border: none !important;
  box-shadow: none !important;
  background: none !important;
}

/* ─────────── LOADER — spinning campus artifact ─────────── */
load-spinner, .load-spinner, #load-spinner { background: none !important; }
load-spinner::before, .load-spinner::before, #load-spinner::before {
  content: var(--dku-loader) !important;
  display: block !important;
  font-size: 24px;
  width: 64px !important;
  height: 64px !important;
  line-height: 64px;
  text-align: center;
  transform-origin: 50% 50% !important;
  animation: dku-loader-spin 2.8s linear infinite !important;
}
load-spinner::after, .load-spinner::after, #load-spinner::after { content: "" !important; display: none !important; }

/* ─────────── MOBILE — thumb-friendly, no jank ─────────── */
@media (max-width: 1000px) {
  :root { --dku-avatar-h: 290px; }
  ::-webkit-scrollbar { display: none !important; width: 0 !important; height: 0 !important; }
  html, body, #chat, #sheld, .mes, .mes_block, .mes_text, .mes_reasoning {
    scrollbar-width: none !important;
    -ms-overflow-style: none !important;
  }
  .mes .mes_block, .mes .mes_buttons { overflow: visible !important; }
  .mes .ch_name .name_text { font-size: 16px; }
  .mes .mesIDDisplay, .mes .tokenCounterDisplay, .mes .mes_timer {
    font-size: 10px !important;
    padding: 3px 8px !important;
  }
  .mes .mes_timer { top: 52px !important; }
  #nonQRFormItems { margin: 6px 4px; }
  #form_sheld { padding-bottom: env(safe-area-inset-bottom); }
  #chat .mes, body.bubblechat .mes { margin-bottom: 40px !important; border-radius: 18px !important; }
  #nonQRFormItems:has(#send_textarea:placeholder-shown)::before { font-size: 10px; max-width: calc(100% - 84px); }
  #top-bar, body.no-blur #top-bar { border-radius: 0 0 16px 16px !important; }
}
@media (max-width: 480px) {
  :root { --dku-avatar-h: 250px; }
  .mes .ch_name .name_text { font-size: 14px; letter-spacing: 0.08em; }
  .swipe_left { margin-right: 66px !important; }
  .swipe_right { margin-left: 66px !important; }
}
